import time, random
def retry_with_backoff(fn, max_retries=5):
    for attempt in range(max_retries):
        try:
            return fn()
        except Exception as e:
            if attempt == max_retries - 1:
                raise
            wait = min(60, (2 ** attempt)) + random.uniform(0, 1)
            time.sleep(wait)

