CREATE ROW ACCESS POLICY region_policy AS (region_col STRING) RETURNS BOOLEAN ->
  CASE WHEN CURRENT_ROLE() = 'us_analyst' THEN region_col = 'US'
       WHEN CURRENT_ROLE() = 'eu_analyst' THEN region_col = 'EU'
       ELSE TRUE END;
ALTER TABLE gold.sales ADD ROW ACCESS POLICY region_policy ON (region);

